import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const Register = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [role, setRole] = useState('user');
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        console.log('📝 Регистрация:', { username, role }); // 🔍 Лог для отладки

        try {
            await register(username, password, role);
            console.log('✅ Успешная регистрация');
            navigate('/products');
        } catch (err) {
            console.error('❌ Ошибка регистрации:', err);
            setError('Ошибка регистрации. Возможно, username уже существует.');
        }
    };

    return (
        <div style={styles.container}>
            <h2>Регистрация</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit} style={styles.form}>
                <div style={styles.formGroup}>
                    <label>Username:</label>
                    <input
                        type="text"
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                        required
                        style={styles.input}
                    />
                </div>
                <div style={styles.formGroup}>
                    <label>Пароль:</label>
                    <div style={styles.passwordContainer}>
                        <input
                            type={showPassword ? 'text' : 'password'}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            style={styles.input}
                        />
                        <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            style={styles.eyeButton}
                        >
                            {showPassword ? '🙈' : '👁️'}
                        </button>
                    </div>
                </div>
                <div style={styles.formGroup}>
                    <label>Роль:</label>
                    <select 
                        value={role} 
                        onChange={(e) => setRole(e.target.value)}
                        style={styles.input}
                    >
                        <option value="user">👤 Пользователь</option>
                        <option value="seller">🏪 Продавец</option>
                        <option value="admin">👑 Администратор</option>
                    </select>
                </div>
                <button type="submit" style={styles.button}>Зарегистрироваться</button>
            </form>
            <p>
                Уже есть аккаунт? <Link to="/login">Войти</Link>
            </p>
        </div>
    );
};

const styles = {
    container: { maxWidth: '400px', margin: '50px auto', padding: '20px' },
    form: { display: 'flex', flexDirection: 'column', gap: '15px' },
    formGroup: { display: 'flex', flexDirection: 'column', gap: '5px' },
    input: { padding: '10px', fontSize: '16px', flex: 1 },
    button: { padding: '10px', fontSize: '16px', cursor: 'pointer' },
    error: { color: 'red', marginBottom: '10px' },
    passwordContainer: { display: 'flex', gap: '5px', alignItems: 'center' },
    eyeButton: {
        padding: '10px',
        fontSize: '18px',
        cursor: 'pointer',
        border: '1px solid #ccc',
        backgroundColor: '#f5f5f5',
        borderRadius: '4px',
    },
};

export default Register;
